import heapq
def merge_k(lists):
    heap=[]
    for i,lst in enumerate(lists):
        if lst:heapq.heappush(heap,(lst[0],i,0))
    result=[]
    while heap:
        val,i,j=heapq.heappop(heap)
        result.append(val)
        if j+1<len(lists[i]):heapq.heappush(heap,(lists[i][j+1],i,j+1))
    return result
print(merge_k([[1,4,5],[1,3,4],[2,6]]))

from collections import deque
class Node:
    def __init__(self,v):self.val=v;self.left=self.right=None
def serialize(root):
    if not root:return ""
    q=deque([root]);res=[]
    while q:
        node=q.popleft()
        if node:res.append(str(node.val));q.append(node.left);q.append(node.right)
        else:res.append("null")
    return ",".join(res)
