root.right.left=Node(4);root.right.right=Node(5)
print(serialize(root))

from collections import defaultdict,deque
def alien_order(words):
    adj=defaultdict(set);in_deg={c:0 for w in words for c in w}
    for i in range(len(words)-1):
        w1,w2=words[i],words[i+1]
        for c1,c2 in zip(w1,w2):
            if c1!=c2:
                if c2 not in adj[c1]:adj[c1].add(c2);in_deg[c2]+=1
                break
    q=deque([c for c in in_deg if in_deg[c]==0]);res=""
    while q:
        c=q.popleft();res+=c
        for nb in adj[c]:
            in_deg[nb]-=1
            if in_deg[nb]==0:q.append(nb)
    return res if len(res)==len(in_deg) else ""
print(alien_order(["wrt","wrf","er","ett","rftt"]))

def is_match(s,p):
    m,n=len(s),len(p)
    dp=[[False]*(n+1) for _ in range(m+1)]
    dp[0][0]=True
    for j in range(1,n+1):
        if p[j-1]=="*":dp[0][j]=dp[0][j-2]
    for i in range(1,m+1):
        for j in range(1,n+1):
            if p[j-1]=="*":
                dp[i][j]=dp[i][j-2] or(dp[i-1][j] and(p[j-2]==s[i-1] or p[j-2]=="."))
            elif p[j-1]==s[i-1] or p[j-1]==".":dp[i][j]=dp[i-1][j-1]
    return dp[m][n]
print(is_match("aa","a*"))

from collections import deque
def max_sliding(nums,k):
    dq=deque();res=[]
    for i,n in enumerate(nums):
        while dq and dq[0]<i-k+1:dq.popleft()
        while dq and nums[dq[-1]]<n:dq.pop()
        dq.append(i)
        if i>=k-1:res.append(nums[dq[0]])
    return res
print(max_sliding([1,3,-1,-3,5,3,6,7],3))

def can_finish(n,prereqs):
    adj=[[] for _ in range(n)]
    for a,b in prereqs:adj[b].append(a)
    state=[0]*n
    def dfs(node):
        if state[node]==1:return False
        if state[node]==2:return True
        state[node]=1
        for nb in adj[node]:
            if not dfs(nb):return False
        state[node]=2;return True
    return all(dfs(i) for i in range(n))
print(can_finish(2,[[1,0],[0,1]]))

class Trie:
    def __init__(self):self.children={};self.end=False
    def insert(self,w):
        node=self
        for c in w:
            if c not in node.children:node.children[c]=Trie()
            node=node.children[c]
        node.end=True
    def search(self,w):
        node=self
        for c in w:
            if c not in node.children:return False
            node=node.children[c]
        return node.end
    def startsWith(self,p):
        node=self
        for c in p:
            if c not in node.children:return False
            node=node.children[c]
        return True
